<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Assign') }}{{ $t('Tag') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm"
                            v-on:OnSubmit="onSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import DataService from '../../services/DataService'
export default{
    props:{
        ProjectIds:{
            type: String,
            required: true,
        }
    },
    data(){        
        return{
            isLoading:false,
            AssignTagList:[],          
            FormSchema: [               
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "CustomSelectField",
                            mode: "tag",                           
                            label: this.$t('Tag'),
                            name: "Tag",
                            value: "",
                            config: {
                                options: [],
                               
                            },
                            placeholder: this.$t('Select Tag'),
                            validationRules: { "required": true, max: 100 },
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true                   
                    
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }        
    },
    created:function(){
        var vm=this;        
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.onAssignTagList();
    },
    methods:{
        onAssignTagList:function(){
            var ths=this;
            var url = `id=&moduleName=PROJECT&type=HR_TAG&search=&refId=`;
            DataService.GetDDLData(url).then((response)=>{
                if (response.data && response.data.DATA) {
                    response.data.DATA.forEach((item)=>{
                        let obj={
                            name:item.name,
                            value:item.value
                        }                        
                        ths.FormSchema[0].Data[0].config.options.push(obj);
                    })
                    ths.$refs.AssignTagForm.UpdateKeyValue();
                }
            })
        },
        Close:function(){
             this.$emit('CallBackFunction');
        },
        onSubmit:function(){      
            var vm=this;
            if(vm.ProjectIds != ''){
                const valuesArray = vm.FormSchema[0].Data[0].value;
                const resultString = valuesArray.map(item => item.value).join(',');                
                var VarObject = {
                    ID: vm.ProjectIds,
                    TagId: resultString
                }
                var objectPostString = JSON.stringify(VarObject);              
                DataService.CommonAssignTag(objectPostString).then(function (response) {
                    if (response.data.result.MSG== 'SUCCESS') {
                        vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert")); 
                        vm.Close();
                    }
                    else {
                        vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
                    }
                });                
            }
        }
    }
}
</script>