<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t("UploadFile") }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body maxht-scroll tall-body"> <!-- Added tall-body class -->
                        <dynamic-form lang="en" ref="AddTeamForm" :buttons="buttonsss" :schema="FormSchemaaa"
                            v-on:OnSubmit="SaveTeamMemberData" :mandatorytext='MandatoryString'>
                        </dynamic-form>

                        <div class="row">
                            <div class="col-lg-12 mb-3">
                                <div class="heading-border mt-2">
                                    <h5 class="h5"><span>{{ $t('Visibleto') }}</span></h5>
                                </div>
                            </div>
                        </div>
                        <div class="col-md-12 col-lg-12 col-xl-12 float-left p-0 mb-2 lastchild-control"
                            v-for="item in UserData" :key="item.userTypeId" v-if="UserData.length > 0"
                            style="border-bottom: 1px solid #dee2e6; border-top: 1px solid #dee2e6;">
                            <!-- Removed max-height and overflow-y -->
                            <div class="form-group row m-0 border p-2 bg-f5f5f5">
                                <div class="custom-control custom-checkbox">
                                    <input name="usertypes" type="checkbox" :value="item.userTypeId"
                                        :id="'userType-' + item.userTypeId" class="custom-control-input"
                                        v-model="item.ParentSelected" @change="CheckAllUsers($event, item)">
                                    <label class="custom-control-label universal-custom-control-label pt-1"
                                        :for="'userType-' + item.userTypeId"></label>
                                    <span class="clsprivdata ml-1">{{ item.userType }}</span>
                                </div>
                            </div>
                            <ul class="row m-0 p-0 py-3 mb-3 border border-top-0">
                                <li class="col-sm-12 col-md-4 col-lg-3 col-xl-3 float-left pl-2 mb-2"
                                    style="list-style: none;" v-for="obj in item.userses" :key="obj.id">
                                    <div class="custom-control custom-checkbox">
                                        <input name="users" type="checkbox" :value="obj.id" v-model="obj.ChildSelected"
                                            :id="'user-' + obj.id" class="custom-control-input"
                                            @click="ToggleCheck(obj, item)">
                                        <label class="custom-control-label universal-custom-control-label pt-1"
                                            :for="'user-' + obj.id"></label>
                                        {{ obj.name }}
                                    </div>
                                </li>
                            </ul>
                        </div>
                        <div class="col-md-12 col-lg-12 p-0" v-if="UserData.length == 0">
                            <div
                                class="text-center text-danger d-flex align-items-center justify-content-center borderbababa px-2 py-2 no-record">
                                {{ $t('NoRecordfound') }}
                            </div>
                        </div>
                    </div>
                    <div class="col-lg-12 text-right mt-4 mb-3">
                        <a href="javascript:;" title="Save" class="btn btn-success text-white mr-2"
                            @click="SaveTeamMemberData()"><i class="fa fa-upload pr-2"></i>{{ $t('Upload')
                            }}</a>
                        <a title="Cancel" class="btn btn-danger text-white" @click="Close()"><i
                                class="fa fa-close pr-2"></i>{{ $t("Cancel") }}</a>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>

import DataService from '../../services/DataService';

export default
    {
        props: {
            ProjectId: {
                type: Number,
                required: true,
            },
            Screen: {
                type: String
            }
        },
        data() {
            return {
                userId: null,
                companyId: null,
                UserType: null,
                UserData: [],
                UsersType: null,
                MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
                FormSchemaaa: [
                    {
                        layoutType: "single",
                        Data: [
                            {
                                astype: "TextField",
                                label: this.$t('FileTitle'),
                                name: "File Title",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                            }
                        ]
                    },
                    {
                        layoutType: "single",
                        Data: [
                            {
                                astype: "FileField",
                                label: this.$t('Attachment'),
                                name: "avatar",
                                value: "",
                                placeholder: "Enter Avatar",
                                config: {
                                    mode: "date",
                                    options: [],
                                    dependentOn: null,
                                    showWhen: null,
                                    valueMapping: null,
                                    fieldCode: null,
                                    maxSize: 100,
                                    accept: [
                                        {
                                            fileType: 'jpg',
                                            iconClass: 'fa-file-image-o'
                                        },
                                        {
                                            fileType: 'jpeg',
                                            iconClass: 'fa-file-image-o'
                                        },
                                        {
                                            fileType: 'png',
                                            iconClass: 'fa-file-image-o'
                                        },
                                        {
                                            fileType: 'pdf',
                                            iconClass: 'fa-file-archive-o'
                                        },
                                        {
                                            fileType: 'mp4',
                                            iconClass: 'fa-video-camera'
                                        },
                                        {
                                            fileType: 'doc',
                                            iconClass: 'fa-file-text-o'
                                        },
                                        {
                                            fileType: 'docx',
                                            iconClass: 'fa-file-text-o'
                                        },
                                        {
                                            fileType: 'xlsx',
                                            iconClass: 'fa-file-excel-o'
                                        },
                                        {
                                            fileType: 'txt',
                                            iconClass: 'fa-file-text-o'
                                        },
                                        {
                                            fileType: 'xls',
                                            iconClass: 'fa-file-excel-o'
                                        }

                                    ],
                                    onChange: this.previewFiles

                                },
                                mode: "",
                                isibility: true,
                                validationRules: {
                                    required: true,
                                    max: 200
                                },
                            }
                        ]
                    },
                    {
                        layoutType: "single",
                        Data: [
                            {
                                astype: "TextAreaField",
                                label: this.$t('Description'),
                                name: "Description",
                                value: "",
                                validationRules: { "required": true, max: 4000 },
                                config: {
                                    rows: 2
                                }
                            }
                        ]
                    }
                ],

                isAllSelected: false,
                ImageData: [],
                Userids: '',
                filePath: '',
                file: '',
                IsProcessing: false,
                SelectedIds: [],
                isLoading: false,
                FileId: 0,
                contentType:null,
                buttonsss:[],
                

            }
        },
        created: function () {
            var ths = this;
            ths.userId = ths.GetUserInfo.ID;
            ths.companyId = ths.GetUserInfo.CompanyId;
            ths.UserType = ths.GetUserInfo.UserType;
            ths.FetchUserListing();
        },
        methods: {
            FetchUserListing: function () {
                var ths = this;
                ths.isLoading = true;
                var url = `projectId=${ths.ProjectId}`;
                DataService.UserList(url).then((response) => {
                    const result = response.data.result || [];
                    const grouped = {};
                    result.forEach(user => {
                        if (!grouped[user.user_type_id]) {
                            grouped[user.user_type_id] = {
                                userTypeId: user.user_type_id,
                                userType: user.user_type_desc,
                                ParentSelected: false,
                                userses: []
                            };
                        }
                        grouped[user.user_type_id].userses.push({
                            id: user.user_id,
                            name: user.name,
                            ChildSelected: false
                        });
                    });

                    this.UserData = Object.values(grouped);
                });
                ths.isLoading = false;
            },
            Close: function () {
                var vm = this;
                vm.$parent.IsFileUploadModalShow = false;
            },
            CheckAllUsers(event, item) {
                var vm = this;
                this.UserData.forEach(element => {
                    if (event.target.checked == true) {
                        if (element.userTypeId == item.userTypeId) {
                            element.userses.forEach(ele => {
                                ele.ChildSelected = true;
                                if (ele.ChildSelected) {
                                    vm.SelectedIds.push(ele.id);
                                }
                            })
                        }
                    } else {
                        if (element.userTypeId == item.userTypeId) {
                            element.userses.forEach(ele => {
                                ele.ChildSelected = false;
                            })
                        }
                    }
                })
                vm.Userids = vm.SelectedIds.join(",");
            },

            ToggleCheck(Cobject, Pobject) {
                var vm = this;
                const user = Pobject.userses.find(user => user.id === Cobject.id);
                if (user) {
                    user.ChildSelected = !user.ChildSelected;
                }
                if (Cobject.ChildSelected) {
                    vm.SelectedIds.push(Cobject.id);
                } else {
                    const index = vm.SelectedIds.indexOf(Cobject.id);
                    if (index > -1) {
                        vm.SelectedIds.splice(index, 1);
                    }
                }
                const totalUsersesLength = Pobject.userses.length;
                const checkedChildSelectedCount = Pobject.userses.filter(user => user.ChildSelected === true).length;
                if (totalUsersesLength == checkedChildSelectedCount) {
                    Pobject.ParentSelected = true;
                }
                else {
                    Pobject.ParentSelected = false;
                }
                vm.Userids = vm.SelectedIds.join(",");
            },
            previewFiles(event) {
                const file = event.target.files && event.target.files[0];
                this.selectedFile = file || null;
                this.getFileName = file ? file.name : '';
                this.contentType = {
                    "ContentType": file ? file.type : null,
                    "Size":file ? file.size : null,
                    "Extension":file ? file.name.substring(file.name.lastIndexOf('.')) : null
                }
            },
            SaveTeamMemberData: async function () {                
                var vm = this;
               
                const result = await vm.$refs.AddTeamForm.validateForm.validate();
                if (!result) {
                    return;
                }
                if (vm.selectedFile == null) {
                    vm.ShowAlert(vm.$t('Selectatleastonefile'), "failure", true, vm.$t("Alert"));
                    return;
                }
                debugger
                vm.isLoading = true;
                if (vm.selectedFile) {
                    var uploadedInfo = await vm.uploadToDocStorage(vm.selectedFile);                    
                    if (uploadedInfo) {
                        var fileUrl = uploadedInfo.FilePath;
                        var FileName = uploadedInfo.FileName;   
                        var FileThumb = uploadedInfo.FileThumbPath;                 
                        const formData = new FormData();
                        var VarObject = {
                            FileTitle: vm.FormSchemaaa[0].Data[0].value,
                            FileName:FileName,
                            Description: vm.FormSchemaaa[2].Data[0].value,
                            FilePath: fileUrl,
                            ProjectId: vm.ProjectId,
                            TaskId: null,
                            UserIds: vm.Userids,
                            FileId: 0,
                            ContentType: vm.contentType,
                            FileThumb:FileThumb
                        }
                        formData.append("postString", JSON.stringify(VarObject));                        
                        await DataService.SaveTeamMember(formData).then((response) => {                            
                            if (response.data == 1) {
                                vm.isLoading = false;
                                vm.ShowAlert("File Added Successfully!", "success", true, vm.$t("Alert"));
                                let payload = {
                                    projectId: vm.ProjectId,
                                    projectName: 'text',
                                    projectContent: `${VarObject.UserIds} ${vm.$t('uploaded')} ${VarObject.FileTitle}`,
                                };
                                DataService.SendAddProjectNotification(JSON.stringify(payload)).then((res) => {
                                    console.log("Notification Response:", res.data);
                                });
                                if (vm.Screen == 'Files') {
                                    vm.$emit('GetFilesListing');
                                    vm.$parent.IsFileUploadModalShow = false;
                                    vm.$parent.IsNewVersionUpload = false;
                                }
                                else {
                                    vm.$emit('GetFilesListing');
                                    vm.$parent.IsFileUploadModalShow = false;
                                    vm.$parent.IsNewVersionUpload = false;
                                }
                            }
                            else if (response.data == 3) {
                                vm.ShowAlert("FileAlreadyExists", "warning", true, vm.$t("Alert"));
                            }
                        });
                    }
                }                
            },
            async uploadToDocStorage(file) {
                const vm = this;
                const formData = new FormData();
                formData.append("fileId", vm.FileId || 0);
                formData.append("folderId", 0);
                formData.append("moduleName", "PROJECT");
                formData.append("subModuleName", "");
                formData.append("isGlobal", 0);
                formData.append("file", file);
                formData.append("contentType", file.type);
                const response = await DataService.UploadStreamNew(formData);
                const newdata = response && response.data ? response.data : null;
                if (!newdata) {
                    throw new Error("Empty response from DocStorage upload");
                }
                if (newdata.UploadStatus !== 1) {
                    throw new Error(newdata.ErrorMsg || "DocStorage upload failed");
                }
                return newdata;
            },

        }
    }
</script>

<style scoped>
.tall-modal .modal-content {
    height: 100%;
    /* Full height of the dialog */
    display: flex;
    flex-direction: column;
}

.tall-modal .modal-body {
    flex: 1;
    /* Allows body to expand and take available space */
    overflow-y: visible;
    /* Removes scroll by setting to visible */
    max-height: none;
    /* Removes any max-height limit */
}

/* Override any existing maxht-scroll class */
.maxht-scroll {
    max-height: none !important;
    overflow-y: visible !important;
}
</style>
