<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('StatusUpdate') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="UpdateForm"
                            v-on:OnSubmit="onSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService'
export default{
    props:{
        ProjectIds:{
            type: String,
            required: true,
        }
    },
    data(){        
        return{
            isLoading:false,
            ProjectStatusList:[],
            ProjectStatusId:'',
            StatusColor: '#ffffff',
            StatusBgColor: '#525f65',
            FormSchema: [               
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SelectField",                           
                            label: this.$t('Status'),
                            name: "Status",
                            value: "",
                            config: {
                                options: [],
                                onChange: this.ChangeStatus
                            },
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": true, max: 100 },
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:false,                    
                    onClick: this.OnSubmit
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }        
    },
    created:function(){
        var vm=this;        
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.onProjectStatusList();
    },
    methods:{
        onProjectStatusList:function(){
            var ths=this;
            var url=`langCode=en&companyId=${this.companyId}&&statusType=Project&hasglobal=true`
            DataService.onStatusList(url).then((response)=>{                
                if(response.data.result.data.length>0){
                    response.data.result.data.forEach((item)=>{
                        let obj={
                            name:item.STATUS,
                            value:item.STATUS_ID
                        }                        
                        ths.FormSchema[0].Data[0].config.options.push(obj);
                    })
                    ths.$refs.UpdateForm.UpdateKeyValue();
                }
            })
        },
        Close:function(){
            this.$parent.IsUpdateStatusProject=false
        },
        ChangeStatus:function(){         
            var vm=this;
            if(vm.ProjectIds != ''){
                vm.confirmR(vm.$t("ConfirmUpdateStatusRecord"), true, (vm.$t("Delete") + "  " + vm.$t("Active/Inactive")), function () { 
                    var obj = {
                        ID: vm.ProjectIds,
                        StatusId: vm.FormSchema[0].Data[0].value,
                        IsFor: 'PROJECTLISTING'
                    };
                    var objectPostString = JSON.stringify(obj)               
                    DataService.CommonUpdateStatus(objectPostString).then(function (response) {
                        if (response.data.result== '0') {
                            vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                            vm.Close();
                            vm.$parent.FetchData();
                        }
                        else {
                            vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
                        }
                    });
                });
            }
        }
    }
}

</script>