        FetchData: async function () {
            const vm = this;
            vm.isLoading = true;
            vm.isLoadingg = false;
            try {
                const url = `subModuleCode=Project_Detail&moduleName=PROJECT&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&langCode=en&searchCondition=${vm.searchCondition}&fav=${vm.fav}`;

                const { data } = await DataService.ProjectListing(url);
                if (!data?.result) return;

                const result = data.result;
                /* ---------------------------
                   HEADER OPTIMIZATION
                ----------------------------*/
                const slotColumns = new Set([
                    'priority_id', 'status_id',
                    'planned_start_date', 'planned_end_date',
                    'current_progress', 'estimated_hours',
                    'currency_conversion_rate', 'estimated_cost',
                    'project_cost', 'project_name',
                    'industry_type_id', 'template_id'
                ]);
                vm.Headers = result.schema.map(column => {
                    column.DISPLAY_NAME = vm.$t(column.DISPLAY_NAME, column.COLUMN_NAME);
                    if (column.DATA_TYPE === 'date') column.DATA_TYPE = 'DATE';
                    if (['select', 'string'].includes(column.DATA_TYPE))
                        column.DATA_TYPE = 'text';
                    if (slotColumns.has(column.COLUMN_NAME)) {
                        column.settings = { isInSlot: true };
                    }
                    return column;
                });
                /* ---------------------------
                   DATA OPTIMIZATION
                ----------------------------*/
                vm.ProjectData = (result.data || []).map(item => {
                    if (item.is_sample_data == 1) {
                        item.additionalClass = "sample-bar";
                    }
                    // ✅ Correct date condition
                    if (item.planned_start_date)
                        item.planned_start_date = new Date(item.planned_start_date);

                    if (item.planned_end_date)
                        item.planned_end_date = new Date(item.planned_end_date);

                    return item;
                });
                vm.isLoadingg = true;
                vm.TotalRecords = result.total_records?.[0] || 0;
                vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                vm.CurrentPage = vm.PageNumber;

                /* ---------------------------
                   BUTTON DISABLE OPTIMIZED
                ----------------------------*/
                [0, 4, 5, 6].forEach(i => {
                    if (vm.listheaderbuttons[i])
                        vm.listheaderbuttons[i].isdisabled = true;
                });

                /* ---------------------------
                   WIDGET OPTIMIZED
                ----------------------------*/
                vm.widgets[0].value = result.total_records?.[0] || 0;
                vm.widgets[1].value = result.inprogress_project?.[0] || 0;
                vm.widgets[2].value = result.total_revenue_project?.length
                    ? vm.$n(result.total_revenue_project[0], 'currency', vm.$getLocaleByCurrency(vm.CurrencyCode))
                    : 0;
                vm.widgets[3].value = result.completed_project?.[0] || 0;
                vm.widgets[4].value = result.closed_project?.[0] || 0;

                vm.GetDdlRecords_ViewList();

            } catch (error) {
                console.error(error);
            } finally {
                vm.isLoading = false;
            }
        },
        renderActions: function (row) {
