                        break;
                    case 'Clone Project':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ? true : false;
                        break;
                    case 'Make it default':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ? true : false;
                        break;
                    case 'Configurations':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ? true : false;
