                    box.classList.remove('is-visible');
                }
            });
            const actionBox = document.getElementById('action-list-box-' + projectId);
            if (actionBox) {
                const isVisible = actionBox.style.display === 'block';
                if (isVisible) {
                    // Close if already open
                    actionBox.style.display = 'none';
                    actionBox.style.opacity = '0';
                    actionBox.style.width = '0';
                    actionBox.classList.remove('is-visible');
                } else {
                    // Open if closed
                    actionBox.style.display = 'block';
                    actionBox.style.opacity = '1';
                    actionBox.style.width = '240px';
                    actionBox.classList.add('is-visible');
                }
            }
        },
        closeActionIcon(e, projectId) {
            e.stopPropagation();
            const actionBox = document.getElementById('action-list-box-' + projectId);
            if (actionBox) {
                actionBox.style.display = 'none';
                actionBox.style.opacity = '0';
                actionBox.style.width = '0';
                actionBox.classList.remove('is-visible');
            }
        },
        resetAllCardStates() {
            var vm = this;
            $('[id^="showdiv"]').hide();
            $('a.read-more-content[id^="a"]').show();
            const allActionBoxes = document.querySelectorAll('.action-list-box');
            allActionBoxes.forEach(box => {
                box.style.display = 'none';
                box.style.opacity = '0';
                box.style.width = '0';
                box.classList.remove('is-visible');
            });
            vm.ShowMoreFalse = false;
        },
        HideIsAddTeamShow() {
            this.IsAddTeamShow = false;
            this.$router.push({ name: 'ProjectList' });
        }
    },   
    beforeDestroy() {
        if (this.handleClickOutside) {
            document.removeEventListener('click', this.handleClickOutside);
        }
    }

}
</script>
